#nullable enable // autogenerated

using MVZ2.Vanilla.Entities;
using MVZ2Logic.Entities;
using PVZEngine.Definitions;
using PVZEngine.Entities;

namespace MVZ2.GameContent.Effects
{
    [AutoEntityBehaviourDefinition(VanillaEntityBehaviourNames.setAnimationVariant)]
    public class SetAnimationVariantBehaviour : EntityBehaviourDefinition
    {
        public SetAnimationVariantBehaviour(string nsp, string name) : base(nsp, name)
        {
        }
        public override void Init(Entity entity)
        {
            base.Init(entity);
            entity.SetAnimationInt("Variant", entity.GetVariant());
        }
        public override void Update(Entity entity)
        {
            base.Update(entity);
            entity.SetAnimationInt("Variant", entity.GetVariant());
        }

    }
}